import React, { useState} from 'react';
import ExpenseDate from "./ExpenseDate";
import Card from "../UI/Card";
import './ExpenseItem.css';

const ExpenseItem = (props) => {
    // Expenses žóźžĄú ExpensesItemžĚĄ ŽĄ§Ž≤ą žā¨žö©ŪēīžĄú žĹėžÜĒžĚī 4Ž≤ąžįćŪěė
    // console.log('4Ž≤ą žįćŪěąÍ≤†žßÄ?');
    // Í∑łžĻėŽßĆ Ž≤ĄŪäľžĚĄ ŪĀīŽ¶≠ŪēėŽ©ī žĹėžÜĒžĚÄ 1Ž≤ąŽßĆ žįćŪěąÍ≤Ć ŽźúŽč§
    // žĚīžú†ŽäĒ ŪäĻž†ē žĚłžä§ŪĄīžä§ŽßĆ žóÖŽćįžĚīŪäł ŽźėžóąÍłį ŽēĆŽ¨łžóź

    const [title, setTitle] = useState(props.title);
    // title : žÉĀŪÉúÍįí   setTitle : ÍįížĚĄ žóÖŽćįžĚīŪäłŪēėŽäĒ Ūē®žąė


    const clickHndler = () => {
        setTitle('update');
    }

    return(
        <Card className="expense-item">
            <ExpenseDate date={props.date} />
            {/*dateŪėēžčĚžĚÄ Žāīžě•Ž©ĒžÜĆŽďúžĚł toISOStringžĚĄ Ūėłž∂úŪēīžēľŪē®*/}
            <div className="expense-item__description">
                <h2>{title}</h2>
                <div className="expense-item__price">${props.amount}</div>
            </div>
            <button onClick={clickHndler}>Change Title</button>
        </Card>
    );
}

export default ExpenseItem;
